// Calculate date range for the past week
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const since = weekAgo.toISOString();
const until = now.toISOString();

// Filter merged PRs from the closed PRs
const closedPrs = $input.all();
const allClosedPrs = closedPrs.flatMap(item => item.json);

const mergedPrs = allClosedPrs.filter(pr => {
  if (!pr.merged_at) return false;
  const mergedAt = new Date(pr.merged_at);
  return mergedAt >= weekAgo && mergedAt <= now;
});

// Filter closed issues (exclude PRs)
const allClosedIssues = closedPrs.filter(item => !item.json.pull_request);

// Extract commit data
const commitsData = $('Fetch Commits').all();
const commits = commitsData.flatMap(item => item.json).map(c => ({
  sha: c.sha,
  message: c.commit.message.split('\n')[0],
  author: c.commit.author.name,
  date: c.commit.author.date
}));

// Extract issues data
const issues = allClosedIssues.map(i => ({
  number: i.json.number,
  title: i.json.title,
  state: i.json.state,
  closed_at: i.json.closed_at
}));

// Create summary input
const summaryInput = {
  since,
  until,
  repo: $vars.GITHUB_REPO,
  commits: commits.slice(0, 20), // limit to 20
  issues: issues.slice(0, 20),   // limit to 20
  mergedPRs: mergedPrs.slice(0, 20).map(pr => ({
    number: pr.number,
    title: pr.title,
    merged_at: pr.merged_at
  }))
};

return [{ json: summaryInput }];

