// Extract the summary from Claude's response
const claudeResponse = $input.first().json;
const summary = claudeResponse.content?.[0]?.text || JSON.stringify(claudeResponse);

const language = $vars.LANGUAGE || 'EN';
const repo = $vars.GITHUB_REPO || 'unknown/repo';

const title = language === 'FR' 
  ? `📊 Résumé Hebdomadaire Dev - ${repo}`
  : `📊 Weekly Developer Summary - ${repo}`;

const webhookPayload = {
  content: `${title}\n\n${summary}`
};

return [{ json: webhookPayload }];
